    fn archive_patcher_executor_aborts_before_mutation_when_manifest_write_fails() {
        let records = vec![archive(
            "Game/Data/A.ba2",
            ArchiveFormat::General,
            ArchiveVersion::NextGen8,
            true,
        )];
        let fs = FakeFilesystem::default()
            .with_dir("Game/Data")
