        let digest = patch_digest(&fs, &records, ArchivePatcherTarget::OldGen);

        let error = ArchivePatcherService::new(&fs)
            .execute_confirmed(
                ArchivePatcherExecutionRequest::new(
                    6,
                    Some(&data_root()),
                    &records,
                    ArchivePatcherTarget::OldGen,
                    None,
                    &manifest_path(),
                )
                .with_confirmed_plan_digest(&digest),
