        selected_source: UpdateSource,
        releases: Vec<UpdateRelease>,
    ) -> Self {
        if releases.is_empty() {
            Self::NoUpdate { selected_source }
        } else {
            Self::Available {
                selected_source,
                releases,
            }
        }
    }

    /// Creates a silent-failure state for configured sources.
