fn emit_archive_patcher_execution_log_rows<S>(
    context: &workers::WorkerTaskContext<S>,
    request_id: u64,
    stage: ArchivePatcherWorkerStage,
    result: &ArchivePatcherExecutionResult,
) where
    S: WorkerEventSink,
{
    for row in &result.log_rows {
